properties.script:
// -------------------------------------------------------------------------
// Poll Orthanc REST API for new DICOM studies
//
// State is persisted in globalChannelMap between ticks:
//   orthanc_last_seq  : last processed Orthanc change sequence number
//   orthanc_queue     : JSON array of pending study IDs to process
// -------------------------------------------------------------------------

var ORTHANC_BASE = 'http://10.10.10.15:8042';

// Helper: HTTP GET → parsed JSON
function httpGet(path) {
  var url = new java.net.URL(ORTHANC_BASE + path);
  var conn = url.openConnection();
  conn.setRequestMethod('GET');
  conn.setRequestProperty('Accept', 'application/json');
  conn.setConnectTimeout(5000);
  conn.setReadTimeout(10000);

  var code = conn.getResponseCode();
  if (code !== 200) {
    logger.warn('Orthanc HTTP ' + code + ' for ' + path);
    return null;
  }

  var reader = new java.io.BufferedReader(
    new java.io.InputStreamReader(conn.getInputStream(), 'UTF-8')
  );
  var sb = new java.lang.StringBuilder();
  var line;
  while ((line = reader.readLine()) !== null) {
    sb.append(line);
  }
  reader.close();
  return JSON.parse(sb.toString());
}

// ---- Read state ----
var lastSeq = globalChannelMap.get('orthanc_last_seq') || 0;
var queueRaw = globalChannelMap.get('orthanc_queue');
var queue = queueRaw ? JSON.parse(queueRaw) : [];

// ---- If queue has pending studies, return the next one ----
if (queue.length > 0) {
  var studyId = queue.shift();
  globalChannelMap.put('orthanc_queue', JSON.stringify(queue));

  var study = httpGet('/studies/' + studyId);
  if (!study) return null;

  logger.info('Orthanc study ready for HL7: ' + studyId);
  return JSON.stringify(study);
}

// ---- Queue is empty: fetch new changes from Orthanc ----
var changes = httpGet('/changes?since=' + lastSeq + '&limit=100');
if (!changes) return null;

var newStudyIds = [];
for (var i = 0; i < changes.Changes.length; i++) {
  var c = changes.Changes[i];
  if (c.ChangeType === 'NewStudy') {
    newStudyIds.push(c.ID);
  }
}

// Update last processed sequence
if (changes.Last !== undefined) {
  globalChannelMap.put('orthanc_last_seq', changes.Last);
}

if (newStudyIds.length === 0) return null;

// Process first study now, queue the rest
var firstId = newStudyIds.shift();
if (newStudyIds.length > 0) {
  globalChannelMap.put('orthanc_queue', JSON.stringify(newStudyIds));
}

var firstStudy = httpGet('/studies/' + firstId);
if (!firstStudy) return null;

logger.info('New Orthanc study detected: ' + firstId +
  ' Modality=' + (firstStudy.MainDicomTags && firstStudy.MainDicomTags.Modality || 'UNKNOWN'));
return JSON.stringify(firstStudy);

com.mirth.connect.plugins.javascriptrule.script:
var study = JSON.parse(msg);
var tags  = study.MainDicomTags      || {};
var ptags = study.PatientMainDicomTags || {};

channelMap.put('study_id',           study.ID                          || '');
channelMap.put('study_instance_uid', tags.StudyInstanceUID             || '');
channelMap.put('study_date',         tags.StudyDate                    || '');
channelMap.put('study_time',         tags.StudyTime                    || '');
channelMap.put('modality',           tags.Modality                     || 'OT');
channelMap.put('study_description',  tags.StudyDescription             || '');
channelMap.put('accession_number',   tags.AccessionNumber              || '');
channelMap.put('patient_id',         ptags.PatientID                   || 'GIZMO_PATIENT_001');
channelMap.put('patient_name',       ptags.PatientName                 || 'Paciente^Virtual');
channelMap.put('referring_physician',tags.ReferringPhysicianName       || '');

logger.info('Study metadata extracted: PatientID=' + ptags.PatientID +
  ' Modality=' + tags.Modality + ' UID=' + tags.StudyInstanceUID);

// -----------------------------------------------------------------------
// Build HL7 v2.5.1 ORU^R01 — Radiology study completed notification
// Carries the DICOM StudyInstanceUID so OpenEMR can link to the image
// stored in Orthanc (10.10.10.15:8042)
// -----------------------------------------------------------------------
var studyUID   = channelMap.get('study_instance_uid') || '';
var studyDate  = channelMap.get('study_date')         || '';
var studyTime  = channelMap.get('study_time')         || '';
var modality   = channelMap.get('modality')           || 'OT';
var studyDesc  = channelMap.get('study_description')  || '';
var accession  = channelMap.get('accession_number')   || '';
var patientId  = channelMap.get('patient_id')         || 'GIZMO_PATIENT_001';
var patientName= channelMap.get('patient_name')       || 'Paciente^Virtual';
var physician  = channelMap.get('referring_physician')|| '';

var now = new Date();
function pad(n) { return n < 10 ? '0' + n : '' + n; }
var hl7ts = '' + now.getFullYear() +
  pad(now.getMonth()+1) + pad(now.getDate()) +
  pad(now.getHours()) + pad(now.getMinutes()) + pad(now.getSeconds());

var msgId = 'DICOM' + hl7ts;
var studyDT = studyDate + studyTime;

// LOINC 18748-4 = Diagnostic imaging study
// LOINC 110180-7 = Study instance UID
// DICOM CID 121022 = Source of Measurement (StudyInstanceUID)
var lines = [
  'MSH|^~\\&|ORTHANC|HOSPITAL_GIZMO|MIRTH_CONNECT|OPENEMR|' + hl7ts +
    '||ORU^R01^ORU_R01|' + msgId + '|P|2.5.1|||AL|AL|',

  'PID|1||' + patientId + '^^^HOSPITAL_GIZMO&HOSPITAL&L||' + patientName +
    '||19800101|U|',

  // OBR — radiology order/result
  'OBR|1||' + accession + '|18748-4^Diagnostic imaging study^LN|||' +
    studyDT + '|||' + physician + '||||||' + studyDT + '|||' + modality +
    '|||||||||F',

  // OBX 1 — StudyInstanceUID (DICOM reference — allows OpenEMR to open in Orthanc viewer)
  'OBX|1|RP|110180-7^Study Instance UID^LN||' + studyUID +
    '^' + modality + '^ORTHANC&http://10.10.10.15:8042&ISO|||||F|||' + hl7ts,

  // OBX 2 — Modality
  'OBX|2|ST|59847-4^Imaging modality^LN||' + modality + '|||||F|||' + hl7ts,

  // OBX 3 — Study description
  'OBX|3|ST|32484-8^Study description^LN||' + studyDesc + '|||||F|||' + hl7ts,

  // OBX 4 — Orthanc viewer URL (direct link to study)
  'OBX|4|RP|113014^Referenced SOP Instance^DCM||http://10.10.10.15:8042/app/explorer.html' +
    '#study?uuid=' + channelMap.get('study_id') + '|||||F|||' + hl7ts,
];

tmp = lines.join('\r');

// Build a FHIR R4 ImagingStudy resource for the completed TAC/DICOM study
var studyUID  = channelMap.get('study_instance_uid') || '';
var modality  = channelMap.get('modality')           || 'CT';
var studyDate = channelMap.get('study_date')         || '';
var studyDesc = channelMap.get('study_description')  || '';
var patientId = channelMap.get('patient_id')         || 'gizmo-patient-001';
var accession = channelMap.get('accession_number')   || '';

// ISO date from DICOM YYYYMMDD
var started = studyDate.length === 8
  ? studyDate.substring(0,4) + '-' + studyDate.substring(4,6) + '-' + studyDate.substring(6,8) + 'T00:00:00Z'
  : new Date().toISOString();

var resource = {
  resourceType: 'ImagingStudy',
  status: 'available',
  subject: {reference: 'Patient/' + patientId.toLowerCase()},
  started: started,
  identifier: [
    {system: 'urn:dicom:uid', value: 'urn:oid:' + studyUID},
    {system: 'http://hospital.gizmo/accession', value: accession}
  ],
  modality: [{
    system: 'http://dicom.nema.org/resources/ontology/DCM',
    code: modality
  }],
  description: studyDesc,
  endpoint: [{
    reference: 'Endpoint/orthanc-wado',
    display: 'Orthanc WADO-RS — http://10.10.10.15:8042'
  }],
  note: [{
    text: 'Study stored in Orthanc. View at http://10.10.10.15:8042/app/explorer.html'
  }]
};

tmp = JSON.stringify(resource, null, 2);
